#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=30005;
int n,t1,t2,t3,dp[N],ans=0x3f3f3f3f;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	memset(dp,0x3f,sizeof(dp));
	cin>>n;
	dp[0]=0;
	for(int i=1;i<=n;i++)
	{
		cin>>t1>>t2>>t3;
		for(int j=30000;j>=0;j--)
		{
			int x=0x3f3f3f3f,y,z;
			y=z=x;
			if((t1!=0)&&(j>=t1)) x=dp[j-t1];
			if(t2!=0) y=dp[j]+t2;
			if((t3!=0)&&(j>=t3)) z=dp[j-t3]+t3;
			dp[j]=min(x,min(y,z));
//			dbg(dp[j]);
		}
//		cout<<"__________________\n";
	}
	for(int i=0;i<=30000;i++)
	{
		ans=min(ans,max(i,dp[i]));
	}
	cout<<ans;
	return 0;
}
